252→/// Convert a `SymExpr` into a Z3 AST node, declaring variables as needed.
253→///
254→/// `hint_sort` is used to determine the sort of `Param` nodes when no other
255→/// information is available.
256→///
257→/// Must be called within a `z3::with_z3_config` block or with the default
258→/// thread-local Z3 context active.
259→fn to_z3_expr(
260→    vars: &mut VarTable,
261→    expr: &SymExpr,
262→    hint_sort: Sort,
263→) -> Result<Z3Ast, SolverError> {
264→    match expr {
265→        SymExpr::Param { name, path } => {
266→            let var_name = param_var_name(name, path);
267→            // Use declared param sort to prevent sort mismatches (e.g. string params
268→            // declared as Int when they appear inside .length). Only override hint_sort
269→            // when the declared sort is categorically different (Str vs numeric/bool).
270→            // For numeric sorts (Int/Real/Float), prefer the comparison context's hint
271→            // since TS `number` maps to Float but constraints often use Int comparisons.
272→            let sort = match vars.param_sorts.get(&var_name).copied() {
273→                Some(declared) if !sorts_compatible(declared, hint_sort) => declared,
274→                _ => hint_sort,
275→            };
276→            match sort {
277→                Sort::Int => Ok(Z3Ast::Int(vars.get_or_create_int(&var_name))),
278→                Sort::Real => Ok(Z3Ast::Real(vars.get_or_create_real(&var_name))),
279→                Sort::Bool => Ok(Z3Ast::Bool(vars.get_or_create_bool(&var_name))),
280→                Sort::Str => Ok(Z3Ast::Str(vars.get_or_create_string(&var_name))),
281→            }
282→        }
283→
284→        SymExpr::Const(c) => match c {
285→            ConstValue::Int(v) => Ok(Z3Ast::Int(Int::from_i64(*v))),
286→            ConstValue::Float(v) => {
287→                let scaled = (*v * 1_000_000.0).round() as i64;
288→                Ok(Z3Ast::Real(Real::from_rational(scaled, 1_000_000)))
289→            }
290→            ConstValue::Str(s) => Ok(Z3Ast::Str(Z3String::from_str(s).map_err(|_| {
291→                SolverError::Unsupported("failed to create Z3 string constant".into())
292→            })?)),
293→            ConstValue::Bool(b) => Ok(Z3Ast::Bool(Bool::from_bool(*b))),
294→            ConstValue::Null | ConstValue::Undefined => Ok(Z3Ast::Int(Int::from_i64(0))),
295→            // Complex constants unwrap to their repr for solving
296→            ConstValue::Complex { repr, .. } => {
297→                let unwrapped = SymExpr::Const(*repr.clone());
298→                to_z3_expr(vars, &unwrapped, hint_sort)
299→            }
300→        },
301→
302→        SymExpr::BinOp { op, left, right } => convert_binop(vars, *op, left, right, hint_sort),
303→
304→        SymExpr::UnOp { op, operand } => convert_unop(vars, *op, operand, hint_sort),
305→
306→        SymExpr::Call {
307→            name,
308→            receiver,
309→            args,
310→        } => convert_string_call(vars, name, receiver.as_deref(), args),
311→
312→        SymExpr::Unknown => Err(SolverError::Unsupported(
313→            "unknown expression cannot be represented in Z3".into(),
314→        )),
315→    }
316→}
